  1→/**
  2→ * BLP1 image decoder — reads Warcraft III .blp texture files
  3→ * and converts them to data URLs for use in <img> and CSS backgrounds.
  4→ *
  5→ * Supports JPEG-content BLP1 images (the most common WC3 format).
  6→ */
  7→
  8→enum BlpType {
  9→  BLP0 = 0,
 10→  BLP1 = 1,
 11→  BLP2 = 2,
 12→}
 13→
 14→enum BlpContent {
 15→  JPEG = 0,
 16→  Direct = 1,
 17→}
 18→
 19→interface BlpImage {
 20→  type: BlpType;
 21→  width: number;
 22→  height: number;
 23→  content: BlpContent;
 24→  alphaBits: number;
 25→  mipmaps: Array<{ offset: number; size: number }>;
 26→  data: ArrayBuffer;
 27→}
 28→
 29→function readString(view: DataView, offset: number): string {
 30→  let s = "";
 31→  for (let i = 0; i < 4; i++) {
 32→    s += String.fromCharCode(view.getUint8(offset + i));
 33→  }
 34→  return s;
 35→}
 36→
 37→function parseBlp(buffer: ArrayBuffer): BlpImage {
 38→  const view = new DataView(buffer);
 39→  const img: BlpImage = {
 40→    type: BlpType.BLP1,
 41→    width: 0,
 42→    height: 0,
 43→    content: BlpContent.JPEG,
 44→    alphaBits: 0,
 45→    mipmaps: [],
 46→    data: buffer,
 47→  };
 48→
 49→  const magic = readString(view, 0);
 50→  if (magic === "BLP0" || magic === "BLP2") {
 51→    throw new Error("BLP0/BLP2 not supported");
 52→  }
 53→  if (magic !== "BLP1") {
 54→    throw new Error("Not a BLP image");
 55→  }
 56→
 57→  img.content = view.getUint32(4, true) as BlpContent;
 58→  img.alphaBits = view.getUint32(8, true);
 59→  img.width = view.getUint32(12, true);
 60→  img.height = view.getUint32(16, true);
 61→
 62→  for (let i = 0; i < 16; i++) {
 63→    const offset = view.getUint32(28 + i * 4, true);
 64→    const size = view.getUint32(92 + i * 4, true);
 65→    if (size > 0) {
 66→      img.mipmaps.push({ offset, size });
 67→    }
 68→  }
 69→
 70→  return img;
 71→}
 72→
 73→function blpToImageData(img: BlpImage): ImageData | null {
 74→  if (img.content === BlpContent.JPEG && img.mipmaps.length > 0) {
 75→    // JPEG content: header + mipmap data
 76→    const headerSize = new DataView(img.data).getUint32(160, true);
 77→    const header = new Uint8Array(img.data, 164, headerSize);
 78→    const mip = img.mipmaps[0];
 79→    const mipData = new Uint8Array(img.data, mip.offset, mip.size);
 80→
 81→    // Combine JPEG header + mipmap body
 82→    const jpegData = new Uint8Array(headerSize + mip.size);
 83→    jpegData.set(header);
 84→    jpegData.set(mipData, headerSize);
 85→
 86→    return null; // For JPEG, we use blob URL approach instead
 87→  }
 88→
 89→  if (img.content === BlpContent.Direct) {
 90→    // Palette-based: 256-color palette at offset 156
 91→    const palette = new Uint32Array(img.data, 156, 256);
 92→    const mip = img.mipmaps[0];
 93→    if (!mip) return null;
 94→
 95→    const indices = new Uint8Array(img.data, mip.offset, mip.size);
 96→    const w = img.width;
 97→    const h = img.height;
 98→    const pixelCount = w * h;
 99→    const imageData = new ImageData(w, h);
100→    const pixels = imageData.data;
101→
102→    for (let i = 0; i < pixelCount; i++) {
103→      const color = palette[indices[i]];
104→      pixels[i * 4] = color & 0xff;
105→      pixels[i * 4 + 1] = (color >> 8) & 0xff;
106→      pixels[i * 4 + 2] = (color >> 16) & 0xff;
107→      pixels[i * 4 + 3] = 255;
108→    }
109→
110→    // Handle alpha channel
111→    if (img.alphaBits > 0) {
112→      const alphaOffset = mip.offset + pixelCount;
113→      const alphaData = new Uint8Array(img.data, alphaOffset);
114→      if (img.alphaBits === 8) {
115→        for (let i = 0; i < pixelCount; i++) {
116→          pixels[i * 4 + 3] = alphaData[i];
117→        }
118→      } else if (img.alphaBits === 4) {
119→        for (let i = 0; i < pixelCount; i++) {
120→          const byte = alphaData[Math.floor(i / 2)];
121→          const nibble = i % 2 === 0 ? byte & 0xf : (byte >> 4) & 0xf;
122→          pixels[i * 4 + 3] = nibble * 17;
123→        }
124→      } else if (img.alphaBits === 1) {
125→        for (let i = 0; i < pixelCount; i++) {
126→          const byte = alphaData[Math.floor(i / 8)];
127→          const bit = (byte >> (i % 8)) & 1;
128→          pixels[i * 4 + 3] = bit * 255;
129→        }
130→      }
131→    }
132→
133→    return imageData;
134→  }
135→
136→  return null;
137→}
138→
139→/**
140→ * Load a BLP file from a URL and return a data URL.
141→ * This is the primary way to use BLP textures in React components.
142→ */
143→export async function loadBlpDataUrl(url: string): Promise<string> {
144→  const response = await fetch(url);
145→  const buffer = await response.arrayBuffer();
146→  const img = parseBlp(buffer);
147→
148→  if (img.content === BlpContent.JPEG) {
149→    // For JPEG BLP: extract JPEG data and create blob URL
150→    const headerSize = new DataView(buffer).getUint32(160, true);
151→    const header = new Uint8Array(buffer, 164, headerSize);
152→    const mip = img.mipmaps[0];
153→    if (!mip) throw new Error("No mipmap data");
154→
155→    const mipData = new Uint8Array(buffer, mip.offset, mip.size);
156→    const jpegData = new Uint8Array(headerSize + mip.size);
157→    jpegData.set(header);
158→    jpegData.set(mipData, headerSize);
159→
160→    const blob = new Blob([jpegData], { type: "image/jpeg" });
161→    return URL.createObjectURL(blob);
162→  }
163→
164→  // For palette-based BLP: render to canvas
165→  const imageData = blpToImageData(img);
166→  if (!imageData) throw new Error("Failed to decode BLP");
167→
168→  const canvas = document.createElement("canvas");
169→  canvas.width = img.width;
170→  canvas.height = img.height;
171→  const ctx = canvas.getContext("2d");
172→  if (!ctx) throw new Error("Canvas 2D context unavailable");
173→  ctx.putImageData(imageData, 0, 0);
174→
175→  return canvas.toDataURL("image/png");
176→}
177→
178→/**
179→ * Load a BLP file and return it as an HTMLImageElement (for canvas drawing).
180→ */
181→export async function loadBlpImage(url: string): Promise<HTMLImageElement> {
182→  const dataUrl = await loadBlpDataUrl(url);
183→  return new Promise((resolve, reject) => {
184→    const img = new Image();
185→    img.onload = () => resolve(img);
186→    img.onerror = reject;
187→    img.src = dataUrl;
188→  });
189→}
