30→  const canvasRef = useRef<HTMLCanvasElement>(null);
31→  const percent = max > 0 ? Math.min(100, Math.max(0, (value / max) * 100)) : 0;
32→
33→  useEffect(() => {
34→    let cancelled = false;
35→
36→    async function render() {
37→      const canvas = canvasRef.current;
38→      if (!canvas) return;
39→      const ctx = canvas.getContext("2d");
40→      if (!ctx) return;
41→
42→      try {
43→        const [fill, highlight, edge] = await Promise.all([
44→          loadBlpImage(fillUrl),
45→          loadBlpImage(highlightUrl),
46→          loadBlpImage(edgeUrl),
47→        ]);
