59→          ctx.beginPath();
60→          ctx.rect(0, 0, fillW, h);
61→          ctx.clip();
62→          ctx.drawImage(fill, 0, 0, w, h);
63→          ctx.restore();
64→        }
65→
66→        // Draw highlight
67→        if (fillW > 0) {
68→          ctx.save();
69→          ctx.globalCompositeOperation = "screen";
70→          ctx.globalAlpha = 0.62;
71→          ctx.beginPath();
72→          ctx.rect(0, 0, fillW, h);
73→          ctx.clip();
74→          ctx.drawImage(highlight, 0, 0, w, h);
75→          ctx.restore();
76→        }
77→
78→        // Draw edge
79→        ctx.drawImage(edge, 0, 0, w, h);
80→      } catch {

