16→ * The pressed background is race-specific while the check mark and base are shared.
17→ */
18→export function Checkbox({
19→  checked,
20→  onChange,
21→  disabled = false,
22→  race = "Human",
23→  className,
24→}: CheckboxProps) {
25→  const [pressed, setPressed] = useState(false);
26→
27→  const bgUrl = useBlpTexture(
28→    disabled ? CHECKBOX_ASSETS.bgDisabled : CHECKBOX_ASSETS.bg,
29→  );
30→  const checkUrl = useBlpTexture(CHECKBOX_ASSETS.check);
31→  const depressedUrl = useBlpTexture(getCheckboxDepressed(race));
32→
33→  const handleClick = () => {
34→    if (!disabled) onChange?.(!checked);
35→  };
36→
37→  return (
38→    <button
39→      type="button"
40→      className={`esc-checkbox ${className ?? ""}`}
41→      role="checkbox"
42→      aria-checked={checked}
43→      onClick={handleClick}
44→      disabled={disabled}
45→      onMouseDown={() => setPressed(true)}
46→      onMouseUp={() => setPressed(false)}
47→      onMouseLeave={() => setPressed(false)}
48→      style={disabled ? { cursor: "default" } : undefined}
49→    >
50→      {bgUrl && <img src={bgUrl} alt="" />}
51→      {pressed && depressedUrl && <img src={depressedUrl} alt="" />}
52→      {checked && checkUrl && <img src={checkUrl} alt="" />}
53→    </button>
54→  );
55→}
