/**
 * WC3 Components — Warcraft III themed React UI component styles.
 *
 * Import this stylesheet once at your app's entry point:
 *   import "wc3-components/src/wc3.css";
 *
 * Font: Friz Quadrata must be self-hosted at /fonts/FRIZQT__.TTF
 * or override the font-family via CSS custom properties.
 */

@font-face {
  font-family: Friz Quadrata;
  src: url(../fonts/FRIZQT__.TTF) format("truetype");
  font-weight: 400;
  font-style: normal;
  font-display: swap;
}
:root {
  --card-bg: #111118;
  --card-border: #222233;
  --wc3-white: #ffffff;
  --wc3-gold: #fcd312;
  --wc3-dark-gold: #cca300;
  --wc3-game-cursor: auto;
}
body,
body * {
  cursor: var(--wc3-game-cursor) !important;
}
.viewport {
  position: absolute;
  inset: 0;
  overflow: auto;
  pointer-events: auto;
  padding: 24px 32px;
  padding-top: calc(4vw + 12px);
}
.viewport::-webkit-scrollbar {
  width: 8px;
}
.viewport::-webkit-scrollbar-track {
  background: #111;
}
.viewport::-webkit-scrollbar-thumb {
  background: #333;
  border-radius: 4px;
}
.tab-content {
  max-width: 1100px;
  margin: 0 auto;

