/**
 * Load a texture file from a URL and return a usable image URL.
 * Supports both BLP textures (decoded to data URL) and standard
 * image formats (PNG/JPG/etc.) which are returned as-is.
 */
export async function loadBlpDataUrl(url: string): Promise<string> {
  // Standard image formats don't need decoding
  if (/\.(png|jpe?g|gif|webp|svg)(\?|$)/i.test(url)) {
    return url;
  }

  const response = await fetch(url);
  const buffer = await response.arrayBuffer();
  const img = parseBlp(buffer);

