import React, { useState } from "react";
import { useBlpTexture } from "../hooks/useBlpTexture";
import { COMMAND_BUTTON_ASSETS } from "../utils/assets";
import type { CommandButtonData } from "../types";

export interface CommandButtonProps extends CommandButtonData {
  onClick?: () => void;
  /** Show at 64px showcase size instead of 48px */
  showcase?: boolean;
  className?: string;
}

/**
 * In-game command card ability button with pressed, disabled,
 * cooldown, passive, level-up, and no-resources states.
 */
export function CommandButton({
  icon,
  disabledIcon,
  hotkey,
  label,
  disabled = false,
  passive = false,
  levelUp = false,
  noResources = false,
  cooldown = false,
  onClick,
  showcase = false,
  className,
}: CommandButtonProps) {
  const [pressed, setPressed] = useState(false);
  const [hovered, setHovered] = useState(false);

  const backdropUrl = useBlpTexture(COMMAND_BUTTON_ASSETS.backdrop);
  const frameUrl = useBlpTexture(COMMAND_BUTTON_ASSETS.frame);
  const highlightUrl = useBlpTexture(COMMAND_BUTTON_ASSETS.highlight);
  const iconUrl = icon; //useBlpTexture(disabled ? disabledIcon : icon);

  const classNames = [
    "cmd-btn",
    showcase && "cmd-btn--showcase",
    pressed && "cmd-btn--pressed",
    passive && "cmd-btn--passive",
    levelUp && "cmd-btn--levelup",
    noResources && "cmd-btn--no-resources",

