import React, { useEffect, useRef } from "react";
import { loadBlpImage } from "../utils/blp";
import { LOADING_BAR_ASSETS } from "../utils/assets";

export interface LoadingBarProps {
  /** Progress percentage 0–100 */
  percent: number;
  showText?: boolean;
  className?: string;
}

export function LoadingBar({
  percent,
  showText = true,
  className,
}: LoadingBarProps) {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const clamped = Math.min(100, Math.max(0, percent));

  useEffect(() => {
    let cancelled = false;

    async function render() {
      const canvas = canvasRef.current;
      if (!canvas) return;
      const ctx = canvas.getContext("2d");
      if (!ctx) return;

      try {
        const [bg, fill, border, glass, glow] = await Promise.all([
          loadBlpImage(LOADING_BAR_ASSETS.background),
          loadBlpImage(LOADING_BAR_ASSETS.fill),
          loadBlpImage(LOADING_BAR_ASSETS.border),
          loadBlpImage(LOADING_BAR_ASSETS.glass),
          loadBlpImage(LOADING_BAR_ASSETS.glow),
        ]);
        if (cancelled) return;

        const w = canvas.width;
        const h = canvas.height;
        ctx.clearRect(0, 0, w, h);
        ctx.imageSmoothingEnabled = false;

        // Track insets (proportional to the border frame)
        const trackL = Math.round(w * 0.0586);
        const trackR = Math.round(w * 0.0645);
        const trackT = Math.round(h * 0.2656);
        const trackB = Math.round(h * 0.2656);
        const trackW = w - trackL - trackR;
        const trackH = h - trackT - trackB;

        // Background fill across the track
        ctx.save();
        ctx.beginPath();
        ctx.rect(trackL, trackT, trackW, trackH);
        ctx.clip();
        for (let x = trackL; x < trackL + trackW; x += bg.width) {
          ctx.drawImage(bg, x, trackT, bg.width, trackH);
        }
        ctx.restore();

        // Progress fill
        const fillW = Math.round((clamped / 100) * trackW);
        if (fillW > 0) {
          ctx.save();
          ctx.beginPath();
          ctx.rect(trackL, trackT, fillW, trackH);
          ctx.clip();
          for (let x = trackL; x < trackL + fillW; x += fill.width) {
            ctx.drawImage(fill, x, trackT, fill.width, trackH);
          }
          ctx.restore();
        }

        // Border frame
        ctx.drawImage(border, 0, 0, w, h);

        // Glass overlay
        ctx.save();
        ctx.globalAlpha = 1;
        ctx.drawImage(glass, 0, 0, w, h);
        ctx.restore();

        // Glow on filled portion
        if (clamped > 0) {
          ctx.save();
          ctx.globalCompositeOperation = "screen";
          ctx.beginPath();
          ctx.rect(trackL, 0, fillW, h);
          ctx.clip();
          ctx.drawImage(glow, trackL, 0, trackW, h);
          ctx.restore();
        }
      } catch {
        // Asset loading failed silently
      }
    }

    render();
    return () => { cancelled = true; };
  }, [clamped]);

  return (
    <div className={`wc3-bar wc3-bar--loading ${className ?? ""}`}>
      <canvas ref={canvasRef} className="wc3-bar-canvas" width={512} height={64} />
      {showText && (
        <div className="wc3-bar-text">{Math.floor(clamped)}%</div>
      )}
    </div>
  );
}

