  const bgUrl = useBlpTexture(LOADING_BAR_ASSETS.background);
  const fillUrl = useBlpTexture(LOADING_BAR_ASSETS.fill);
  const borderUrl = useBlpTexture(LOADING_BAR_ASSETS.border);
  const glassUrl = useBlpTexture(LOADING_BAR_ASSETS.glass);
  const glowUrl = useBlpTexture(LOADING_BAR_ASSETS.glow);

  const glowOpacity = clamped > 0 ? 1 : 0;

  return (
    <div className={`loading-preview ${className ?? ""}`}>
      <div className="loading-bar-composite">
        <div
          className="lb-track"
          style={{
